// // This module implements a 5-bit synchronous binary counter with an enable signal.
// It has a synchronous reset signal to initialize the count to 31 and decrements its value on each positive edge of the clock signal when the enable signal is high.
module binary_counter_5bit_with_enable(
    input wire clk,
    input wire rst,
    input wire en,
    output reg [4:0] count
);

    always @(posedge clk) begin
        if (rst) begin
            count <= 5'b00000;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
